import React, { useEffect, useState, useCallback } from 'react';
import { GoogleMap, useJsApiLoader, Marker, InfoWindow } from '@react-google-maps/api';
import { useNavigate, useSearchParams } from 'react-router-dom';
import api from '../api';
import { BottomNav } from './Home';

const mapContainerStyle = { width: '100%', height: '100%' };
const defaultCenter = { lat: 43.2220, lng: 76.8512 }; // Almaty

export default function MapPage() {
  const [tasks, setTasks] = useState([]);
  const [selected, setSelected] = useState(null);
  const [center, setCenter] = useState(defaultCenter);
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const category = searchParams.get('category');

  const { isLoaded } = useJsApiLoader({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_KEY || '',
  });

  useEffect(() => {
    const params = { status: 'open' };
    if (category) params.category = category;
    api.get('/tasks', { params }).then(res => setTasks(res.data)).catch(() => {});
  }, [category]);

  useEffect(() => {
    navigator.geolocation?.getCurrentPosition(
      pos => setCenter({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => {}
    );
  }, []);

  if (!isLoaded) {
    return (
      <div className="app-container" style={{ display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '16px 20px', background: 'white', borderBottom: '1px solid var(--border)' }}>
          <div style={{ fontWeight: 800, fontSize: 18 }}>🗺️ Карта задач</div>
        </div>
        <div className="loading"><div className="spinner" /> Загружаем карту...</div>
        <BottomNav />
      </div>
    );
  }

  const tasksWithCoords = tasks.filter(t => t.latitude && t.longitude);

  return (
    <div className="app-container" style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      {/* Header */}
      <div style={{
        padding: '16px 20px', background: 'white',
        borderBottom: '1px solid var(--border)',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between'
      }}>
        <span style={{ fontWeight: 800, fontSize: 18 }}>🗺️ Карта задач</span>
        <span style={{
          background: 'var(--green-pale)', color: 'var(--green)',
          padding: '4px 10px', borderRadius: 20, fontSize: 13, fontWeight: 600
        }}>
          {tasksWithCoords.length} задач
        </span>
      </div>

      {/* Map */}
      <div style={{ flex: 1, position: 'relative' }}>
        <GoogleMap
          mapContainerStyle={mapContainerStyle}
          center={center}
          zoom={13}
          options={{
            disableDefaultUI: false,
            zoomControl: true,
            streetViewControl: false,
            mapTypeControl: false,
          }}
        >
          {tasksWithCoords.map(task => (
            <Marker
              key={task.id}
              position={{ lat: parseFloat(task.latitude), lng: parseFloat(task.longitude) }}
              onClick={() => setSelected(task)}
              icon={{
                url: 'http://maps.google.com/mapfiles/ms/icons/red-dot.png',
              }}
            />
          ))}

          {selected && (
            <InfoWindow
              position={{ lat: parseFloat(selected.latitude), lng: parseFloat(selected.longitude) }}
              onCloseClick={() => setSelected(null)}
            >
              <div style={{ maxWidth: 240, fontFamily: 'Manrope, sans-serif' }}>
                <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>{selected.title}</div>
                {selected.description && (
                  <div style={{ fontSize: 13, color: '#555', marginBottom: 8 }}>
                    {selected.description.slice(0, 80)}...
                  </div>
                )}
                {selected.payment && (
                  <div style={{ fontSize: 13, color: '#16a34a', fontWeight: 600, marginBottom: 4 }}>
                    💰 {selected.payment} ₸
                  </div>
                )}
                {selected.location_name && (
                  <div style={{ fontSize: 12, color: '#888', marginBottom: 8 }}>
                    📍 {selected.location_name}
                  </div>
                )}
                <button
                  onClick={() => navigate(`/tasks/${selected.id}`)}
                  style={{
                    background: '#3a7d2c', color: 'white', border: 'none',
                    padding: '8px 16px', borderRadius: 8, fontWeight: 600,
                    fontSize: 13, width: '100%', cursor: 'pointer'
                  }}
                >
                  Respond
                </button>
              </div>
            </InfoWindow>
          )}
        </GoogleMap>
      </div>

      <BottomNav />
    </div>
  );
}
